frameParser:
/**
 * Parses the most common NMEA 0183 sentence ($GPGGA) into a flat array of fields:
 * latitude, longitude, altitude, satellites, hdop, fixQuality.
 * Returns the six $GPGGA fields the dataset indexes below expect.
 */
function parse(frame) {
    if (frame.indexOf('GPGGA') < 0)
        return [];

    const parts = frame.split(',');
    if (parts.length < 10) return [];

    function nmeaToDeg(value, hemi) {
        if (!value) return 0;
        const dot = value.indexOf('.');
        const deg = parseInt(value.substring(0, dot - 2));
        const min = parseFloat(value.substring(dot - 2));
        const sign = (hemi === 'S' || hemi === 'W') ? -1 : 1;
        return sign * (deg + min / 60.0);
    }

    return [
        nmeaToDeg(parts[2], parts[3]),
        nmeaToDeg(parts[4], parts[5]),
        parseFloat(parts[9]) || 0,
        parseInt(parts[7]) || 0,
        parseFloat(parts[8]) || 0,
        parseInt(parts[6]) || 0
    ];
}
